参考代码模式：
```typescript
avPlayer.on('stateChange', async (state: string, reason: media.StateChangeReason) => {
  switch (state) {
    case 'completed':
    case 'stopped':
      // 切换到下一段音频
      await avPlayer.reset();
      avPlayer.url = nextAudioUrl;
      break;
    case 'initialized':
      await avPlayer.prepare();
      break;
    case 'prepared':
      await avPlayer.play();
      break;
    case 'error':
      // 错误恢复：重置后重新播放当前段
      await avPlayer.reset();
      avPlayer.url = currentAudioUrl;
      break;
  }
});
avPlayer.on('error', (error: BusinessError) => {
  console.error(`AVPlayer error: ${error.code} - ${error.message}`);
});
```
